<template>
  <runner-index v-if="isRegistered === true" />
  <runner-register v-else-if="isRegistered === false" />
</template>

<script>
import RunnerIndex from '../../components/runner/Index.vue'
import RunnerRegister from '../../components/runner/Register.vue'

export default {
  name: 'Runner',
  provide () {
    return {
      updateRegisterStatus: this.getRunnerInformation,
    }
  },
  components: {
    RunnerIndex,
    RunnerRegister,
  },
  data () {
    return {
      isRegistered: null,
    }
  },
  created () {
    if ( ! this.me.show) {
      this.$router.replace ({
        name: 'login',
      })
    }
    this.getRunnerInformation ()
  },
  methods: {
    getRunnerInformation () {
      this.runnersPlaza.getRunner().then((runner) => {
        if (runner.error !== undefined) {
          this.isRegistered = false;
        } else {
          this.isRegistered = true;
        }
      })
    },
  },
}
</script>
